#ifndef GDN_PREFILL_QK8_V16_D128_K_LAST_KERNEL_H_
#define GDN_PREFILL_QK8_V16_D128_K_LAST_KERNEL_H_

#include <cuda.h>
#include <cuda_runtime.h>
#include <torch/extension.h>
#include <c10/cuda/CUDAStream.h>
#include <stdint.h>

#define GDN_CHECK_CUDA(x) TORCH_CHECK((x).is_cuda(), #x " must be a CUDA tensor")
#define GDN_CHECK_CONTIGUOUS(x) TORCH_CHECK((x).is_contiguous(), #x " must be contiguous")
#define GDN_CHECK_DTYPE(x, t) TORCH_CHECK((x).dtype() == (t), #x " has wrong dtype")
#define GDN_CHECK_SHAPE(cond, msg) TORCH_CHECK((cond), msg)

#ifndef CUDA_CHECK
#define CUDA_CHECK(expr) do {                               \
  cudaError_t _err = (expr);                                \
  if (_err != cudaSuccess) {                                \
    TORCH_CHECK(false, "CUDA error: ", cudaGetErrorString(_err)); \
  }                                                         \
} while(0)
#endif

// Constants fixed by spec
static constexpr int kNumQHeads = 8;
static constexpr int kNumKHeads = 8;
static constexpr int kNumVHeads = 16;
static constexpr int kHeadSize  = 128;

// CUDA launcher
void gdn_prefill_qk8_v16_d128_k_last_launch(
    const at::BFloat16* q,          // [T, 8, 128]
    const at::BFloat16* k,          // [T, 8, 128]
    const at::BFloat16* v,          // [T, 16, 128]
    const float* state,             // [N, 16, 128, 128] (k-last: [N,H,V,K])
    const float* A_log,             // [16]
    const at::BFloat16* a,          // [T, 16]
    const float* dt_bias,           // [16]
    const at::BFloat16* b,          // [T, 16]
    const int64_t* cu_seqlens,       // [N+1]
    int64_t num_seqs,
    int64_t total_seq_len,
    float scale,
    at::BFloat16* output,           // [T, 16, 128]
    float* new_state,               // [N, 16, 128, 128] (k-last)
    cudaStream_t stream);

#endif // GDN_PREFILL_QK8_V16_D128_K_LAST_KERNEL_H_

#include "kernel.h"
#include <cuda_fp16.h>
#include <cuda_bf16.h>

#if defined(__CUDA_ARCH__) && __CUDA_ARCH__ >= 800
#define LDMATRIX_SUPPORTED 1
#else
#define LDMATRIX_SUPPORTED 0
#endif

// ---- math helpers (match PyTorch reference semantics closely) ----
__device__ __forceinline__ float softplus_f(float x) {
  // Stable softplus
  // softplus(x) = log1p(exp(x)) ; use piecewise for stability
  if (x > 20.0f) return x;                // exp(x) huge => log1p(exp(x)) ~ x
  if (x < -20.0f) return expf(x);         // exp(x) tiny => log1p(exp(x)) ~ exp(x)
  return log1pf(expf(x));
}

__device__ __forceinline__ float sigmoid_f(float x) {
  // Stable sigmoid
  if (x >= 0.f) {
    float z = expf(-x);
    return 1.f / (1.f + z);
  } else {
    float z = expf(x);
    return z / (1.f + z);
  }
}

__device__ __forceinline__ float bf16_to_f(at::BFloat16 x) {
  __nv_bfloat16 bx = *reinterpret_cast<const __nv_bfloat16*>(&x);
  return __bfloat162float(bx);
}

__device__ __forceinline__ at::BFloat16 f_to_bf16_rn(float x) {
  __nv_bfloat16 bx = __float2bfloat16_rn(x);
  return *reinterpret_cast<at::BFloat16*>(&bx);
}

// Layout helpers (row-major contiguous)
__device__ __forceinline__ int64_t idx_q(int64_t t, int h, int d) {
  // q: [T, 8, 128]
  return (t * kNumQHeads + h) * kHeadSize + d;
}
__device__ __forceinline__ int64_t idx_k(int64_t t, int h, int d) {
  // k: [T, 8, 128]
  return (t * kNumKHeads + h) * kHeadSize + d;
}
__device__ __forceinline__ int64_t idx_v(int64_t t, int hv, int d) {
  // v: [T, 16, 128]
  return (t * kNumVHeads + hv) * kHeadSize + d;
}
__device__ __forceinline__ int64_t idx_a(int64_t t, int hv) {
  return t * kNumVHeads + hv;
}
__device__ __forceinline__ int64_t idx_b(int64_t t, int hv) {
  return t * kNumVHeads + hv;
}
__device__ __forceinline__ int64_t idx_state_k_last(int64_t seq, int hv, int v, int k) {
  // state/new_state: [N, 16, 128, 128] (k-last: [N,H,V,K])
  return (((seq * kNumVHeads + hv) * kHeadSize + v) * kHeadSize + k);
}

// Compute for one (seq, hv). Sequential over time. Parallelize across hv and sequences.
__global__ void gdn_prefill_kernel(
    const at::BFloat16* __restrict__ q,       // [T, 8, 128]
    const at::BFloat16* __restrict__ k,       // [T, 8, 128]
    const at::BFloat16* __restrict__ v,       // [T, 16, 128]
    const float* __restrict__ state,          // [N, 16, 128, 128] k-last
    const float* __restrict__ A_log,          // [16]
    const at::BFloat16* __restrict__ a,       // [T, 16]
    const float* __restrict__ dt_bias,        // [16]
    const at::BFloat16* __restrict__ b,       // [T, 16]
    const int64_t* __restrict__ cu_seqlens,   // [N+1]
    int64_t total_seq_len,
    float scale,
    at::BFloat16* __restrict__ output,        // [T, 16, 128]
    float* __restrict__ new_state)            // [N, 16, 128, 128] k-last
{
  // grid: (num_seqs, 16)
  const int seq = (int)blockIdx.x;
  const int hv  = (int)blockIdx.y; // 0..15

  const int tid = (int)threadIdx.x; // 0..127
  static_assert(kHeadSize == 128, "head_size must be 128");

  const int64_t start = cu_seqlens[seq];
  const int64_t end   = cu_seqlens[seq + 1];
  const int64_t seqlen = end - start;
  if (seqlen <= 0) return;

  // Map hv -> q/k head by repeat_interleave(2) (since 16/8=2)
  const int qh = hv >> 1; // 0..7
  const int kh = hv >> 1; // 0..7

  // Keep one row of state in registers per thread: state_row[k] where v_index = tid
  // state_HKV in reference is [H,K,V], but input/output state is k-last [H,V,K].
  // We store row for fixed V=tid, varying K: state_vk[k] == state[seq,hv,V=tid,K=k]
  float state_vk[kHeadSize];

  #pragma unroll
  for (int kk = 0; kk < kHeadSize; ++kk) {
    float s = 0.f;
    if (state != nullptr) {
      s = state[idx_state_k_last(seq, hv, tid, kk)];
    }
    state_vk[kk] = s;
  }

  // shared buffers for per-token vectors
  __shared__ float sh_k[128];
  __shared__ float sh_q[128];
  __shared__ float sh_v[128];

  // For each token t: compute decay/update, update state, compute output vector
  for (int64_t t = start; t < end; ++t) {
    // Load k/q/v into shared (float) using 128 threads
    float k_i = bf16_to_f(k[idx_k(t, kh, tid)]);
    float q_i = bf16_to_f(q[idx_q(t, qh, tid)]);
    float v_i = bf16_to_f(v[idx_v(t, hv, tid)]);
    sh_k[tid] = k_i;
    sh_q[tid] = q_i;
    sh_v[tid] = v_i;
    __syncthreads();

    // g and beta scalar per (t,hv)
    float a_f = bf16_to_f(a[idx_a(t, hv)]);
    float b_f = bf16_to_f(b[idx_b(t, hv)]);
    float x   = a_f + dt_bias[hv];
    float g   = expf(-expf(A_log[hv]) * softplus_f(x));
    float beta = sigmoid_f(b_f);

    // old_state = g * state
    #pragma unroll
    for (int kk = 0; kk < kHeadSize; ++kk) state_vk[kk] *= g;

    // old_v[k] = k @ old_state  => old_v[l] in reference is size 128 (V-dim)
    // Here old_v[v] = sum_k sh_k[k] * state_vk[k] for each v=tid
    float old_v_tid = 0.f;
    #pragma unroll
    for (int kk = 0; kk < kHeadSize; ++kk) {
      old_v_tid = fmaf(sh_k[kk], state_vk[kk], old_v_tid);
    }

    // new_v = beta*v + (1-beta)*old_v
    float new_v_tid = beta * sh_v[tid] + (1.f - beta) * old_v_tid;

    // Need S1[k] = sum_v state_remove contribution uses old_v vector:
    // state_remove (for each K,V): = k[K] * old_v[V]
    // state_update:               = k[K] * new_v[V]
    // state_new = old_state - state_remove + state_update
    // For fixed V=tid, each thread updates its state_vk[K] by adding k[K]*(new_v_tid - old_v_tid)
    float dv = new_v_tid - old_v_tid;
    #pragma unroll
    for (int kk = 0; kk < kHeadSize; ++kk) {
      state_vk[kk] = fmaf(sh_k[kk], dv, state_vk[kk]);
    }

    // output: o = scale * q @ state_new  (q is 1xK, state_new is KxV => o is V)
    // For each output dimension v=tid: o_tid = scale * sum_k sh_q[k] * state_vk[k]
    float o_tid = 0.f;
    #pragma unroll
    for (int kk = 0; kk < kHeadSize; ++kk) {
      o_tid = fmaf(sh_q[kk], state_vk[kk], o_tid);
    }
    o_tid *= scale;

    // Write output [t,hv,tid]
    output[idx_v(t, hv, tid)] = f_to_bf16_rn(o_tid);

    __syncthreads();
  }

  // Write back new_state in k-last layout [N,H,V,K]
  #pragma unroll
  for (int kk = 0; kk < kHeadSize; ++kk) {
    new_state[idx_state_k_last(seq, hv, tid, kk)] = state_vk[kk];
  }
}

void gdn_prefill_qk8_v16_d128_k_last_launch(
    const at::BFloat16* q,
    const at::BFloat16* k,
    const at::BFloat16* v,
    const float* state,
    const float* A_log,
    const at::BFloat16* a,
    const float* dt_bias,
    const at::BFloat16* b,
    const int64_t* cu_seqlens,
    int64_t num_seqs,
    int64_t total_seq_len,
    float scale,
    at::BFloat16* output,
    float* new_state,
    cudaStream_t stream)
{
  dim3 block(128, 1, 1);
  dim3 grid((unsigned)num_seqs, (unsigned)kNumVHeads, 1);

  gdn_prefill_kernel<<<grid, block, 0, stream>>>(
      q, k, v, state, A_log, a, dt_bias, b, cu_seqlens, total_seq_len, scale, output, new_state);

  CUDA_CHECK(cudaGetLastError());
}

#include <torch/extension.h>
#include <vector>
#include <cmath>
#include "kernel.h"

static inline float default_scale() {
  return 1.0f / std::sqrt((float)kHeadSize);
}

std::vector<torch::Tensor> run(
    torch::Tensor q,          // BF16 [T,8,128]
    torch::Tensor k,          // BF16 [T,8,128]
    torch::Tensor v,          // BF16 [T,16,128]
    torch::Tensor state,      // FP32 [N,16,128,128] or empty/undefined
    torch::Tensor A_log,      // FP32 [16]
    torch::Tensor a,          // BF16 [T,16]
    torch::Tensor dt_bias,    // FP32 [16]
    torch::Tensor b,          // BF16 [T,16]
    torch::Tensor cu_seqlens, // INT64 [N+1]
    c10::optional<double> scale_opt)
{
  GDN_CHECK_CUDA(q);
  GDN_CHECK_CUDA(k);
  GDN_CHECK_CUDA(v);
  GDN_CHECK_CUDA(A_log);
  GDN_CHECK_CUDA(a);
  GDN_CHECK_CUDA(dt_bias);
  GDN_CHECK_CUDA(b);
  GDN_CHECK_CUDA(cu_seqlens);

  GDN_CHECK_CONTIGUOUS(q);
  GDN_CHECK_CONTIGUOUS(k);
  GDN_CHECK_CONTIGUOUS(v);
  if (state.defined() && state.numel() > 0) GDN_CHECK_CONTIGUOUS(state);
  GDN_CHECK_CONTIGUOUS(A_log);
  GDN_CHECK_CONTIGUOUS(a);
  GDN_CHECK_CONTIGUOUS(dt_bias);
  GDN_CHECK_CONTIGUOUS(b);
  GDN_CHECK_CONTIGUOUS(cu_seqlens);

  GDN_CHECK_DTYPE(q, torch::kBFloat16);
  GDN_CHECK_DTYPE(k, torch::kBFloat16);
  GDN_CHECK_DTYPE(v, torch::kBFloat16);
  if (state.defined() && state.numel() > 0) GDN_CHECK_DTYPE(state, torch::kFloat32);
  GDN_CHECK_DTYPE(A_log, torch::kFloat32);
  GDN_CHECK_DTYPE(a, torch::kBFloat16);
  GDN_CHECK_DTYPE(dt_bias, torch::kFloat32);
  GDN_CHECK_DTYPE(b, torch::kBFloat16);
  GDN_CHECK_DTYPE(cu_seqlens, torch::kInt64);

  TORCH_CHECK(q.dim() == 3 && k.dim() == 3 && v.dim() == 3, "q/k/v must be 3D");
  TORCH_CHECK(q.size(1) == kNumQHeads && k.size(1) == kNumKHeads, "q/k head dims must be 8");
  TORCH_CHECK(v.size(1) == kNumVHeads, "v head dim must be 16");
  TORCH_CHECK(q.size(2) == kHeadSize && k.size(2) == kHeadSize && v.size(2) == kHeadSize, "head_size must be 128");
  TORCH_CHECK(a.sizes() == torch::IntArrayRef({q.size(0), kNumVHeads}), "a must be [T,16]");
  TORCH_CHECK(b.sizes() == torch::IntArrayRef({q.size(0), kNumVHeads}), "b must be [T,16]");
  TORCH_CHECK(A_log.numel() == kNumVHeads && dt_bias.numel() == kNumVHeads, "A_log/dt_bias must be [16]");
  TORCH_CHECK(cu_seqlens.dim() == 1, "cu_seqlens must be 1D");

  const int64_t total_seq_len = q.size(0);
  const int64_t len_cu = cu_seqlens.size(0);
  TORCH_CHECK(len_cu >= 2, "cu_seqlens length must be >= 2");
  const int64_t num_seqs = len_cu - 1;

  // total_seq_len == cu_seqlens[-1]
  {
    auto last = cu_seqlens.index({len_cu - 1}).item<int64_t>();
    TORCH_CHECK(last == total_seq_len, "total_seq_len must equal cu_seqlens[-1]");
  }

  if (state.defined() && state.numel() > 0) {
    TORCH_CHECK(state.dim() == 4, "state must be 4D [N,16,128,128]");
    TORCH_CHECK(state.size(0) == num_seqs, "state.size(0) must equal num_seqs");
    TORCH_CHECK(state.size(1) == kNumVHeads && state.size(2) == kHeadSize && state.size(3) == kHeadSize,
                "state shape must be [N,16,128,128]");
  }

  float scale = scale_opt.has_value() ? (float)scale_opt.value() : default_scale();
  if (scale == 0.0f) scale = default_scale();

  auto out = torch::empty({total_seq_len, kNumVHeads, kHeadSize}, torch::TensorOptions().device(q.device()).dtype(torch::kBFloat16));
  auto new_state = torch::empty({num_seqs, kNumVHeads, kHeadSize, kHeadSize}, torch::TensorOptions().device(q.device()).dtype(torch::kFloat32));

  const at::BFloat16* q_ptr = (const at::BFloat16*)q.data_ptr<at::BFloat16>();
  const at::BFloat16* k_ptr = (const at::BFloat16*)k.data_ptr<at::BFloat16>();
  const at::BFloat16* v_ptr = (const at::BFloat16*)v.data_ptr<at::BFloat16>();
  const float* state_ptr = nullptr;
  if (state.defined() && state.numel() > 0) state_ptr = (const float*)state.data_ptr<float>();
  const float* A_log_ptr = (const float*)A_log.data_ptr<float>();
  const at::BFloat16* a_ptr = (const at::BFloat16*)a.data_ptr<at::BFloat16>();
  const float* dt_bias_ptr = (const float*)dt_bias.data_ptr<float>();
  const at::BFloat16* b_ptr = (const at::BFloat16*)b.data_ptr<at::BFloat16>();
  const int64_t* cu_ptr = (const int64_t*)cu_seqlens.data_ptr<int64_t>();
  at::BFloat16* out_ptr = (at::BFloat16*)out.data_ptr<at::BFloat16>();
  float* new_state_ptr = (float*)new_state.data_ptr<float>();

  cudaStream_t stream = c10::cuda::getDefaultCUDAStream();

  gdn_prefill_qk8_v16_d128_k_last_launch(
      q_ptr, k_ptr, v_ptr,
      state_ptr,
      A_log_ptr, a_ptr, dt_bias_ptr, b_ptr,
      cu_ptr,
      num_seqs, total_seq_len,
      scale,
      out_ptr, new_state_ptr,
      stream);

  CUDA_CHECK(cudaDeviceSynchronize());
  return {out, new_state};
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run", &run, "gdn_prefill_qk8_v16_d128_k_last (CUDA)");
}
